  'source-airtable': {
    "prerequisites": [
      "An Airtable account with access to at least one base you want to sync.",
      "An authentication credential: either a Personal Access Token, or registered OAuth integration credentials (client ID and client secret).",
      "The token or OAuth grant must be authorized for the specific bases or workspaces you intend to read, since Airtable scopes resource access per token.",
      "The read scopes data.records:read and schema.bases:read granted to the credential so records and base schema can be retrieved."
    ],
    "authMethods": [
      {
        "name": "Personal Access Token (api_key)",
        "summary": "Maps to the credentials.api_key secret field. Create a Personal Access Token from the Airtable developer hub at airtable.com/create/tokens, assign the data.records:read and schema.bases:read scopes, and grant it access to the target bases or workspaces. The token is sent to the Airtable Web API as an Authorization: Bearer header. Airtable removed legacy API keys in February 2024, so a Personal Access Token is the supported single-credential option."
      },
      {
        "name": "OAuth 2.0",
        "summary": "Maps to the credentials.client_id, credentials.client_secret, credentials.access_token, and credentials.refresh_token secret fields. Register an OAuth integration at airtable.com/create/oauth to obtain a client ID and client secret, then run the authorization-code flow with PKCE against https://airtable.com/oauth2/v1/authorize and exchange the grant code at https://airtable.com/oauth2/v1/token for an access token and refresh token. Access tokens expire after 60 minutes and refresh tokens after 60 days, so the refresh token is used to mint new access tokens."
      }
    ],
    "setupSteps": [
      {
        "title": "Choose an authentication method",
        "body": "Set the credentials config field to one of the two supported methods. Use a Personal Access Token (credentials.api_key) for a single-account internal connection, or OAuth credentials (credentials.client_id, credentials.client_secret, credentials.access_token, credentials.refresh_token) when access is granted by another user's account."
      },
      {
        "title": "Create a Personal Access Token (token method)",
        "body": "Go to airtable.com/create/tokens, select Personal access tokens, click Create token and name it. Click Add a scope and add data.records:read and schema.bases:read. Then add resources via Add a base (or Add all resources) to grant the token access to the bases or workspaces you want to sync. Copy the generated token into credentials.api_key."
      },
      {
        "title": "Register an OAuth integration (OAuth method)",
        "body": "Register your integration at airtable.com/create/oauth to receive a client ID and client secret. Run the authorization-code flow with PKCE: direct the user to https://airtable.com/oauth2/v1/authorize with response_type=code, your scopes (including data.records:read and schema.bases:read), state, code_challenge, and code_challenge_method=S256, then exchange the returned grant code at https://airtable.com/oauth2/v1/token to obtain the access token and refresh token. Provide these in credentials.client_id, credentials.client_secret, credentials.access_token, and credentials.refresh_token."
      },
      {
        "title": "Configure optional connector settings",
        "body": "Optionally set add_base_id_to_stream_name to prefix stream names with the base ID (useful when syncing multiple bases that share table names), and num_workers to control the number of concurrent workers used during extraction. Both fields are optional and can be left at their defaults."
      }
    ],
    "sources": [
      {
        "title": "Airtable Web API OAuth Reference",
        "url": "https://airtable.com/developers/web/api/oauth-reference#authorization-request"
      },
      {
        "title": "Airtable API Deprecation Guidelines | Airtable Support",
        "url": "https://support.airtable.com/docs/airtable-api-deprecation-guidelines"
      }
    ]
  },

