  'source-breezy-hr': {
    "prerequisites": [
      "An active Breezy HR account with access to at least one company workspace.",
      "A Breezy HR API credential: either a Personal Access Token (PAT) or an account email and password used to obtain an access token.",
      "The company identifier (company_id) of the Breezy HR company you want to sync, retrieved from the API."
    ],
    "authMethods": [
      {
        "name": "API key / Personal Access Token (api_key)",
        "summary": "The connector authenticates with an api_key. Breezy HR is stateless and authenticates via the Authorization bearer token header. You can supply a Personal Access Token (PAT), which is sent as Authorization: breezy_pat_<token>. Alternatively, POST /v3/signin with your email and password to obtain a short-lived access_token used as the bearer token. Both secret fields api_key and company_id are required."
      }
    ],
    "setupSteps": [
      {
        "title": "Obtain an API access token",
        "body": "Authenticate against the Breezy HR API at https://api.breezy.hr/v3. Use a Personal Access Token (PAT) sent as the Authorization bearer token in the form Authorization: breezy_pat_<token>, or call POST /v3/signin with your account email and password to receive an access_token. Use this value for the api_key field."
      },
      {
        "title": "Find your company_id",
        "body": "Call GET /v3/companies with your bearer token to list all companies the authenticated user belongs to. Each company object includes an identifier (_id and friendly_id). Use the identifier of the target company for the company_id field. GET /user/details also returns company context keyed by friendly_id for bootstrapping."
      },
      {
        "title": "Configure the connector",
        "body": "Enter the access token or PAT in the required api_key field and the company identifier in the required company_id field. Both fields are secret and required."
      }
    ],
    "sources": [
      {
        "title": "Breezy HR API documentation",
        "url": "https://developer.breezy.hr/"
      }
    ]
  },

