  'source-instagram': {
    "prerequisites": [
      "A Meta (Facebook) developer account at developers.facebook.com.",
      "A Business-type Meta app created in the App Dashboard. If your existing app is not a Business type, create a new app and select Business during creation.",
      "An Instagram professional account (Business or Creator type) connected to the app.",
      "An Instagram User access token. Tokens from Business Login are short-lived (valid 1 hour); tokens generated from the App Dashboard are long-lived (valid 60 days).",
      "Your app's app ID and app secret from the App Dashboard if you intend to exchange a short-lived token for a long-lived one server-side."
    ],
    "authMethods": [
      {
        "name": "Instagram User access token",
        "summary": "Maps to the required access_token secret field. Authenticate API requests with an Instagram User access token obtained either through the Business Login flow (short-lived, expires in 1 hour) or generated directly from the App Dashboard (long-lived, expires in 60 days). The token is passed on requests to endpoints such as /me and /<IG_ID>/media."
      },
      {
        "name": "App credentials for long-lived token exchange (app ID and app secret)",
        "summary": "Maps to the optional client_id (app ID) and client_secret (app secret) secret fields. These come from the App Dashboard and are used in server-side code to exchange a short-lived Instagram User access token for a long-lived one (60-day) via the /access_token endpoint with grant_type=ig_exchange_token. The app secret must never be exposed in client-side code."
      }
    ],
    "setupSteps": [
      {
        "title": "Create a Business-type Meta app",
        "body": "Sign in to developers.facebook.com and create a new app, selecting the Business app type during creation. If you already have a Meta app that is not a Business type, create a new one. Note the app ID and app secret from the App Dashboard for later use."
      },
      {
        "title": "Connect an Instagram professional account",
        "body": "Ensure you have an Instagram professional account (Business or Creator) and associate it with your Meta app so the API can access its media and account data."
      },
      {
        "title": "Obtain an Instagram User access token",
        "body": "Generate an access token either by implementing the Business Login flow (yields a short-lived token valid for 1 hour) or by generating a long-lived token (valid 60 days) directly from the App Dashboard. Provide this value in the required access_token field."
      },
      {
        "title": "(Optional) Configure app credentials for token exchange",
        "body": "If you want to exchange a short-lived token for a long-lived one, provide client_id (app ID) and client_secret (app secret). A server-side GET request to /access_token with grant_type=ig_exchange_token and your client_secret returns a long-lived token. These fields are optional in this connector."
      },
      {
        "title": "Set the optional sync parameters",
        "body": "Optionally set start_date to bound how far back data is pulled, and num_workers to control extraction parallelism. Both are optional, non-secret config fields."
      }
    ],
    "sources": [
      {
        "title": "Instagram Platform Changelog (Meta for Developers)",
        "url": "https://developers.facebook.com/docs/instagram-platform/changelog"
      }
    ]
  },

