  'source-intercom': {
    "prerequisites": [
      "An Intercom account with access to a workspace whose data you want to sync.",
      "An app created in the Intercom Developer Hub (https://app.intercom.io/a/apps/_/developer-hub/app-packages) to obtain an access token or OAuth credentials.",
      "A start_date marking the earliest point in time from which to replicate data (required)."
    ],
    "authMethods": [
      {
        "name": "Access token (private app)",
        "summary": "Map to the access_token secret field. Create an app in the Intercom Developer Hub, open Configure > Authentication, and copy the workspace Access Token (also shown on Test & Publish > Your Workspaces). Intercom sends it as an HTTP Bearer token (Authorization: Bearer <access_token>). Used for accessing your own workspace data."
      },
      {
        "name": "OAuth (public app)",
        "summary": "Map to the client_id and client_secret secret fields. In the Developer Hub, enable 'Use OAuth' on the Authentication page, configure HTTPS redirect URLs and scopes, then find the client_id and client_secret on the app's Basic Information page. The OAuth code-exchange flow yields an access token used to authorize calls on behalf of other workspaces."
      }
    ],
    "setupSteps": [
      {
        "title": "Create an Intercom app in the Developer Hub",
        "body": "Sign in to Intercom and create an app at https://app.intercom.io/a/apps/_/developer-hub/app-packages. This app is where you obtain the access token or OAuth credentials used to authenticate the connector."
      },
      {
        "title": "Obtain your access token",
        "body": "For a private app, open Configure > Authentication in your app and copy the Access Token (it also appears on Test & Publish > Your Workspaces). Provide this value as the connector's required access_token field. Treat the token like a password and keep it confidential."
      },
      {
        "title": "(Alternative) Set up OAuth credentials",
        "body": "If using OAuth, tick 'Use OAuth' on the Developer Hub Authentication page, set HTTPS redirect URLs, and choose the required permission scopes. Copy the client_id and client_secret from the app's Basic Information page and supply them as the connector's client_id and client_secret fields."
      },
      {
        "title": "Set the replication start date",
        "body": "Provide the required start_date to define the earliest point from which the connector replicates Intercom data."
      },
      {
        "title": "Tune optional settings as needed",
        "body": "Optionally adjust the connector's non-secret fields: api_rate_limit, num_workers, lookback_window, and activity_logs_time_step to control throughput and incremental sync behavior."
      }
    ],
    "sources": [
      {
        "title": "Intercom API OpenAPI specification",
        "url": "https://developers.intercom.com/docs/references/rest-api/api.intercom.io/openapi.json"
      }
    ]
  },

