  'source-nexiopay': {
    "prerequisites": [
      "A Nexio account with access to the Nexio Dashboard.",
      "An API user under Settings > User Management whose username and API key you can copy (supplies the username and api_key fields).",
      "The subdomain for your Nexio environment (for example the sandbox vs production host).",
      "A start_date marking the earliest point from which to sync data."
    ],
    "authMethods": [
      {
        "name": "Basic authentication (username + API key)",
        "summary": "Nexio authenticates API requests with HTTP Basic auth. Your Nexio username and API key are Base64-encoded and sent in an `Authorization: Basic <encoded>` header. Obtain both values from the Nexio Dashboard under Settings > User Management by selecting your API user account and copying the username and API key. These map to the connector's `username` and `api_key` (secret) fields."
      }
    ],
    "setupSteps": [
      {
        "title": "Locate your API user credentials",
        "body": "Sign in to the Nexio Dashboard and go to Settings > User Management. Select your API user account, then copy its username and API key. Nexio uses these for HTTP Basic authentication."
      },
      {
        "title": "Provide the username and API key",
        "body": "Enter the copied username into the `username` field and the API key into the `api_key` (secret) field. Nexio Base64-encodes these into the `Authorization: Basic` header on each request."
      },
      {
        "title": "Set the subdomain for your environment",
        "body": "Enter the `subdomain` for the Nexio environment you are connecting to. Nexio exposes separate sandbox and production hosts, so make sure the subdomain matches the environment that issued your credentials."
      },
      {
        "title": "Set the sync start date",
        "body": "Provide a `start_date` to define the earliest date from which the connector should begin syncing records."
      }
    ],
    "sources": [
      {
        "title": "Nexio API documentation",
        "url": "https://docs.nexiopay.com/"
      }
    ]
  },

  'source-ninjaone-rmm': {
    "prerequisites": [
      "A NinjaOne account with system administrator access. Per NinjaOne's documentation, only system administrators may configure OAuth tokens for the NinjaOne API.",
      "An API client application created in NinjaOne under Administration > Apps > API, which issues the credential supplied in the connector's required api_key field.",
      "A start_date value (the connector's required start_date config field) marking the earliest point from which to begin syncing data."
    ],
    "authMethods": [
      {
        "name": "API client credential (OAuth 2.0)",
        "summary": "The connector authenticates with the single required secret field api_key. You register an API client application in NinjaOne (Administration > Apps > API, Client App IDs tab), which issues a Client ID and a Client Secret. NinjaOne's OAuth token configuration lists Client Credentials as an available grant type for machine-to-machine access, which exchanges these credentials for a short-lived bearer access token. Grant the application the Monitoring scope, which grants read-only access to monitoring data and organization structure, sufficient for a read-only source connector. Supply the issued credential as the connector's api_key."
      }
    ],
    "setupSteps": [
      {
        "title": "Sign in as a system administrator",
        "body": "Log in to NinjaOne with an account that has system administrator privileges. NinjaOne restricts OAuth token configuration to system administrators."
      },
      {
        "title": "Create an API client application",
        "body": "Go to Administration > Apps > API, open the Client App IDs tab, and select Add to open the application configuration and create a new API client application."
      },
      {
        "title": "Select the scope and grant type",
        "body": "Assign the Monitoring scope, which grants read-only access to monitoring data and organization structure (Management is for modifying device and organization information and Control is for remote access, neither of which a read-only source requires). Choose the grant type that matches how the connector obtains a token; for unattended machine-to-machine syncing this is the Client Credentials grant."
      },
      {
        "title": "Save and capture the credential",
        "body": "Save the application. NinjaOne issues a Client ID and a Client Secret. Copy and store these immediately."
      },
      {
        "title": "Configure the connector",
        "body": "Enter the captured API client credential into the connector's required api_key field, and set the required start_date field to the earliest date from which data should be synced."
      }
    ],
    "sources": []
  },

