  'source-onesignal': {
    "prerequisites": [
      "A OneSignal account with one or more applications you want to sync.",
      "Each application's App ID and REST API Key (app_api_key), found in the OneSignal dashboard under Settings > Keys & IDs.",
      "Your account-level User Auth Key for account-wide access across applications.",
      "The list of outcome names to retrieve (the outcome_names field), supplied as comma-separated values, for example os__session_duration.count,os__click.count.",
      "A start date (start_date) in ISO 8601 format (YYYY-MM-DDTHH:mm:ssZ) marking the earliest data to sync."
    ],
    "authMethods": [
      {
        "name": "Per-application REST API Key (app_api_key) + App ID",
        "summary": "Each entry in the applications array authenticates with that application's App ID (app_id) and REST API Key (app_api_key). The App ID publicly identifies the OneSignal app, while the REST API Key is a private app-level secret used to read that app's data. Both are found in the OneSignal dashboard under Settings > Keys & IDs."
      },
      {
        "name": "Account-level User Auth Key (user_auth_key)",
        "summary": "The user_auth_key is an account-level (organization) credential that grants access across your OneSignal applications. It is a secret and must be kept confidential. OneSignal treats this as a legacy User Auth Key; provide it from your OneSignal account settings."
      }
    ],
    "setupSteps": [
      {
        "title": "Locate each application's App ID and REST API Key",
        "body": "In the OneSignal dashboard, open each application you want to sync and go to Settings > Keys & IDs. Copy the App ID and the REST API Key for that application. The App ID identifies the app and the REST API Key (app_api_key) is the private app-level secret used to read its data."
      },
      {
        "title": "Obtain your account-level User Auth Key",
        "body": "Retrieve your User Auth Key (user_auth_key) from your OneSignal account settings. This account-level secret authorizes access across your applications. Keep it confidential and store it securely."
      },
      {
        "title": "Add your applications",
        "body": "In the applications field, add one entry per OneSignal app you want to sync. For each entry provide the App ID (app_id) and REST API Key (app_api_key) collected earlier (an internal app name is used only for identification)."
      },
      {
        "title": "Specify the outcome names to retrieve",
        "body": "Set outcome_names to a comma-separated list of the OneSignal outcomes you want to pull, for example os__session_duration.count,os__click.count. Refer to the OneSignal API documentation for the available outcome options for your apps."
      },
      {
        "title": "Set the sync start date",
        "body": "Set start_date to the earliest point from which data should be synced, formatted as an ISO 8601 timestamp (YYYY-MM-DDTHH:mm:ssZ)."
      }
    ],
    "sources": [
      {
        "title": "OneSignal authentication (Keys & IDs)",
        "url": "https://documentation.onesignal.com/docs/accounts-and-keys"
      },
      {
        "title": "OneSignal API reference",
        "url": "https://documentation.onesignal.com/reference"
      }
    ]
  },

