  'source-paystack': {
    "prerequisites": [
      "A Paystack account. Use Test Mode keys to read data before your account is activated, or activate the account to use Live Mode keys for production data.",
      "Your Paystack secret key, found in the Dashboard under Settings then the API Keys & Webhooks tab. Only admins and the primary account owner can view or regenerate the secret key.",
      "A start_date value marking the earliest record to sync (required).",
      "Optionally, a lookback_window_days value to re-read records updated within a trailing window on each sync (optional)."
    ],
    "authMethods": [
      {
        "name": "Secret key (Bearer token)",
        "summary": "Paystack authenticates every request via the HTTP Authorization header using a Bearer token: 'Authorization: Bearer SECRET_KEY'. Supply your account secret key (test keys are prefixed sk_test_, live keys sk_live_) in the connector's secret_key field. Requests without a valid key return 401 Unauthorized, and all requests must use HTTPS."
      }
    ],
    "setupSteps": [
      {
        "title": "Locate your secret key in the Paystack Dashboard",
        "body": "Sign in to the Paystack Dashboard, open the Settings page, and click the API Keys & Webhooks tab. Copy the secret key. Test Mode keys (sk_test_...) work before account activation; Live Mode keys (sk_live_...) require an activated account. If needed, use 'Generate new secret key' to rotate, which requires an admin or primary owner and your password."
      },
      {
        "title": "Provide the secret key to the connector",
        "body": "Enter the copied secret key into the connector's required secret_key field. Keep it confidential and never expose it in client-side code or version control. The connector sends it as 'Authorization: Bearer <secret_key>' on every API call."
      },
      {
        "title": "Set the sync window",
        "body": "Set the required start_date to the earliest point from which records should be synced. Optionally set lookback_window_days to re-fetch records updated within that trailing number of days on each incremental run; leave it unset to use the connector default."
      }
    ],
    "sources": [
      {
        "title": "Paystack API reference",
        "url": "https://paystack.com/docs/api/"
      }
    ]
  },

  'source-pendo': {
    "prerequisites": [
      "A Pendo subscription with the API enabled for your account, hosted in either the US instance (app.pendo.io) or the EU instance (app.eu.pendo.io).",
      "A Pendo user with administrator privileges, since only admins can create and manage integration keys under Settings > Integrations.",
      "An integration key generated in Pendo, supplied to the connector as the required api_key field. Read access is sufficient for extracting data; enable write access on the key only if you also need to push data."
    ],
    "authMethods": [
      {
        "name": "Integration key (API key)",
        "summary": "The Pendo Engage API authenticates with an integration key sent on every request in the x-pendo-integration-key HTTP header. Provide this value as the connector's api_key field. Generate the key in Pendo under Settings > Integrations > Integration Keys; the key is shown only once, so store it securely."
      }
    ],
    "setupSteps": [
      {
        "title": "Sign in to Pendo as an administrator",
        "body": "Log in to your Pendo subscription with an account that has administrator privileges. Integration keys can only be created and managed by admins."
      },
      {
        "title": "Create an integration key",
        "body": "Go to Settings > Integrations > Integration Keys, then select Add Integration Key. Enter a meaningful description so the key is identifiable later. Leave the key as read-only for extracting data; enable write access only if you intend to send data back to Pendo. Save the generated key value immediately, as it is displayed only once."
      },
      {
        "title": "Provide the key to the connector",
        "body": "Enter the integration key as the connector's api_key field. The connector sends it on each request in the x-pendo-integration-key header to authenticate against the Pendo Engage API."
      },
      {
        "title": "Confirm your region",
        "body": "Pendo serves the API from a region-specific host that matches the URL you use to log in: https://app.pendo.io/api/v1 for the US instance or https://app.eu.pendo.io/api/v1 for the EU instance. Make sure the connector targets the host for the region where your subscription is hosted."
      }
    ],
    "sources": [
      {
        "title": "Pendo API reference (engageapi.pendo.io)",
        "url": "https://engageapi.pendo.io/"
      }
    ]
  },

  'source-pennylane': {
    "prerequisites": [
      "A Pennylane account on the Essential plan or higher.",
      "Admin access to the company workspace (available to Executive, Internal Accountant, or External Accountant roles) so you can generate an API token.",
      "A Company API token generated from the Pennylane app, supplied as the connector's api_key field.",
      "A start_time value defining the earliest point from which to replicate data."
    ],
    "authMethods": [
      {
        "name": "Company API token (Bearer)",
        "summary": "The connector authenticates with a single Pennylane Company API token, mapped to the api_key secret field. The token is sent in the Authorization header as 'Bearer <token>'. Generate it in the Pennylane app under Management > Settings > Connectivity > Developers, choosing Read only or Read and write permissions and an expiration period; copy it immediately because it is shown only once and cannot be retrieved later."
      }
    ],
    "setupSteps": [
      {
        "title": "Generate a Company API token",
        "body": "Log in to Pennylane and go to Management > Settings > Connectivity > Developers. Click Generate an API Token, enter a descriptive name, select permissions (Read only is sufficient for a source connector), choose an expiration period, and generate the token. Copy the token immediately, since it is displayed only once and is not stored by Pennylane."
      },
      {
        "title": "Provide the token as api_key",
        "body": "Paste the generated Company API token into the connector's required api_key field. The connector sends it as 'Authorization: Bearer <token>' against the Pennylane Company API base URL https://app.pennylane.com/api/external/v2/."
      },
      {
        "title": "Set the replication start_time",
        "body": "Set the required start_time field to the earliest date from which the connector should begin replicating records. Data on or after this point is retrieved on the initial sync."
      },
      {
        "title": "Verify the credentials",
        "body": "Confirm the token is valid by ensuring the connector can authenticate. You can independently test the same token against the /me endpoint: curl https://app.pennylane.com/api/external/v2/me -H \"Authorization: Bearer <YOUR_COMPANY_API_TOKEN>\"."
      }
    ],
    "sources": []
  },

