  'source-plaid': {
    "prerequisites": [
      "A Plaid Dashboard account (sign up at dashboard.plaid.com). After signup and accepting the terms, Plaid issues your client_id and per-environment secret.",
      "Your client_id (the private identifier for your team), provided in the Dashboard under Developers > Keys.",
      "Your Plaid secret key (one per environment), provided in the same API Keys page. In this connector the secret is supplied via the api_key field.",
      "An access_token for the Item you want to read. Obtain it by running the Plaid Link flow and exchanging the resulting public_token via /item/public_token/exchange. The access_token does not expire and must be stored securely.",
      "A target Plaid environment (plaid_env), either sandbox for test data or production for live data. Production requires separate access approval through the Dashboard, and Items cannot be moved between environments."
    ],
    "authMethods": [
      {
        "name": "Plaid app credentials (client_id + secret)",
        "summary": "Almost all Plaid API endpoints require your client_id together with your secret (supplied here through the api_key field). Plaid accepts them in the request body or as the PLAID-CLIENT-ID and PLAID-SECRET headers. Both are issued per team in the Plaid Dashboard, with a distinct secret for each environment."
      },
      {
        "name": "Item access_token",
        "summary": "Most data endpoints also require an access_token that uniquely identifies a single Item (a user's login at a financial institution). It is created by exchanging a Plaid Link public_token via /item/public_token/exchange, never expires, and must be stored securely. Provide it in the access_token field."
      }
    ],
    "setupSteps": [
      {
        "title": "Create a Plaid Dashboard account",
        "body": "Sign up at dashboard.plaid.com and accept Plaid's terms. After signup, Plaid provisions a live client_id and a secret for your team."
      },
      {
        "title": "Copy your client_id and secret",
        "body": "Open Developers > Keys in the Dashboard. Copy the client_id (private identifier for your team) into the client_id field. Copy the secret for the environment you are targeting into the api_key field. There is a separate secret per environment."
      },
      {
        "title": "Choose the Plaid environment",
        "body": "Set plaid_env to the environment you want to connect to: sandbox for life-like test data, or production for live data. Production access must be requested through the Dashboard, and Items cannot be moved between environments."
      },
      {
        "title": "Generate an access_token for the Item",
        "body": "Run the Plaid Link flow: call /link/token/create, complete Link as the end user to receive a public_token (which expires after 30 minutes), then call /item/public_token/exchange to obtain the permanent access_token. Paste that access_token into the access_token field."
      },
      {
        "title": "Set the optional start date",
        "body": "Optionally set start_date to bound how far back transaction-style data is pulled. Leave it empty to use the connector default."
      }
    ],
    "sources": []
  },

