  'source-strava': {
    "prerequisites": [
      "A Strava account. Sign up at https://www.strava.com/register if you do not already have one.",
      "A registered Strava API application, created at the API settings page https://www.strava.com/settings/api. Creating an app provides the Client ID and Client Secret.",
      "Your numeric Strava athlete ID (athlete_id), required by the connector.",
      "A start date (start_date) marking the earliest point from which to sync data.",
      "An OAuth2 refresh token (refresh_token) generated for your application with the scopes needed for the data you want to read (for example activity:read_all and read_all for private data)."
    ],
    "authMethods": [
      {
        "name": "OAuth2 (refresh token)",
        "summary": "Strava uses OAuth2. The connector authenticates with your application's client_id and client_secret plus a long-lived refresh_token. Strava access tokens expire every 6 hours, so the connector exchanges the refresh_token at the token endpoint (POST https://www.strava.com/oauth/token with grant_type=refresh_token) to obtain fresh access tokens automatically. The client_secret and refresh_token are stored as secret fields."
      }
    ],
    "setupSteps": [
      {
        "title": "Create a Strava account",
        "body": "If you do not have one, register at https://www.strava.com/register. A Strava account is required to create an API application."
      },
      {
        "title": "Register an API application",
        "body": "Go to https://www.strava.com/settings/api and create an application. Set the Authorization Callback Domain (use localhost for local testing, or your real domain in production). After creation, the My API Application page shows your Client ID (client_id) and Client Secret (client_secret). Keep the Client Secret confidential."
      },
      {
        "title": "Authorize and obtain a refresh token",
        "body": "Run the OAuth2 authorization flow: redirect to Strava's authorize endpoint requesting the scopes you need (for example activity:read_all for activity data including private activities, and read_all for private routes and segments). After the user grants consent, Strava returns an authorization code. Exchange it at POST https://www.strava.com/oauth/token with your client_id, client_secret, the code, and grant_type=authorization_code. The response contains the refresh_token (and a 6-hour access_token)."
      },
      {
        "title": "Configure the connector",
        "body": "Provide client_id, client_secret, and refresh_token from your application, along with your numeric athlete_id and the start_date for the sync. The connector uses the refresh_token to mint new access tokens automatically as the 6-hour access tokens expire."
      }
    ],
    "sources": [
      {
        "title": "Strava API authentication",
        "url": "https://developers.strava.com/docs/authentication/"
      },
      {
        "title": "Strava API reference",
        "url": "https://developers.strava.com/docs/reference/"
      }
    ]
  },

