  'destination-teradata': {
    "prerequisites": [
      "Access to a Teradata Vantage instance (free Vantage Express editions are available on Google Cloud, Azure, AWS, or via local virtualization).",
      "A dedicated database user with permissions to create tables and write data (the docs show creating a user such as pm_user with PERM space and granting the privileges it needs).",
      "Network access from Polymetrics to the Teradata host (the host domain name set in the 'host' field).",
      "The host domain name of the Teradata Vantage instance for the required 'host' config field."
    ],
    "authMethods": [
      {
        "name": "Username and password (logon mechanism)",
        "summary": "Authenticate with a Teradata database user and the secret 'logmech.password'. The 'logmech' config field selects the logon mechanism and supports TD2 (the default), LDAP, and BROWSER. The password is supplied via the secret field."
      },
      {
        "name": "SSL/TLS with CA certificate",
        "summary": "Optional transport security configured through the 'ssl' and 'ssl_mode' config fields. Enable 'ssl' to use an SSL connection and set 'ssl_mode' to the desired mode. A trusted CA certificate can be supplied via the secret field 'ssl_mode.ssl_ca_certificate' so the driver can validate the server certificate."
      }
    ],
    "setupSteps": [
      {
        "title": "Provision a Teradata Vantage user",
        "body": "On your Teradata Vantage instance, create or designate a database user that has permission to create tables and write data. The pm docs illustrate creating a dedicated user (for example pm_user) with PERM space and the required grants. Note the host domain name of the instance."
      },
      {
        "title": "Set the host and logon mechanism",
        "body": "Enter the Teradata Vantage host domain name in the required 'host' field. Set 'logmech' to the logon mechanism for your environment: TD2 (the default) for native Teradata credentials, LDAP, or BROWSER. Provide the database password in the 'logmech.password' secret field."
      },
      {
        "title": "Configure the target schema",
        "body": "Set 'schema' to the default database schema used to resolve unqualified object names (it defaults to public). Optionally set 'raw_data_schema' to control where internal raw tables are written (it defaults to pm_internal)."
      },
      {
        "title": "Configure SSL (optional)",
        "body": "Enable 'ssl' to use an SSL connection and set 'ssl_mode' to the mode for connections to the database. To have the driver validate the server certificate, paste the trusted CA certificate into the 'ssl_mode.ssl_ca_certificate' secret field."
      },
      {
        "title": "Tune advanced options (optional)",
        "body": "Add extra JDBC parameters as key=value pairs (separated by &) in 'jdbc_url_params'. Use 'query_band' to set name-value pairs on the Teradata session that identify the request source. 'drop_cascade' enables cascading table drops (risk of data loss) and 'disable_type_dedupe' disables final table type deduplication; leave these at their defaults unless required."
      }
    ],
    "sources": []
  },

  'source-testrail': {
    "prerequisites": [
      "A TestRail instance you can reach over HTTPS. Note its base URL (for example https://YOURNAME.testrail.io/) to use as domain_name.",
      "A TestRail user account with permission to access the projects and data you want to extract. Provide its login as username.",
      "The TestRail API must be enabled for the instance. On hosted (testrail.io) accounts it is enabled by default; on TestRail Server an administrator enables it under Administration > Site Settings > API.",
      "A credential for HTTP Basic authentication: either the account password or an API key generated for that account, supplied as password.",
      "A start_date marking the earliest point from which to sync records."
    ],
    "authMethods": [
      {
        "name": "HTTP Basic authentication (username + password or API key)",
        "summary": "TestRail's API v2 authenticates every request with HTTP Basic auth: the connector sends an Authorization header of 'Basic ' + base64(username:password). Set username to your TestRail login and password to either your account password or an API key generated for that account. Requests are made against the {domain_name}index.php?/api/v2/ endpoint."
      }
    ],
    "setupSteps": [
      {
        "title": "Confirm the API is enabled",
        "body": "TestRail exposes its API only when enabled for the instance. Hosted testrail.io accounts have it on by default. For self-hosted TestRail Server, an administrator enables it under Administration > Site Settings > API. Without this, all API requests are rejected."
      },
      {
        "title": "Obtain a credential (password or API key)",
        "body": "You can authenticate with your account password, but TestRail recommends an API key. Generate one from your TestRail profile under My Settings on the API Keys tab, then copy the generated key. Use this key (or your password) as the password value."
      },
      {
        "title": "Set domain_name",
        "body": "Enter your TestRail instance base URL as domain_name, for example https://YOURNAME.testrail.io/. The connector appends index.php?/api/v2/ to form the API endpoint, so provide the root URL of the instance, not an API path."
      },
      {
        "title": "Set username and password",
        "body": "Set username to the email or login of the TestRail account, and password to that account's password or its API key. These two values form the HTTP Basic credential the connector uses for every request."
      },
      {
        "title": "Set start_date",
        "body": "Provide start_date as the earliest date from which to pull records. The connector uses it as the lower bound for incremental data so older history is skipped."
      }
    ],
    "sources": [
      {
        "title": "Introduction to the TestRail API (official)",
        "url": "https://support.testrail.com/hc/en-us/articles/7077039051284-Introduction-to-the-TestRail-API"
      },
      {
        "title": "Accessing the TestRail API (official authentication guide)",
        "url": "https://support.testrail.com/hc/en-us/articles/7077196481428-Accessing-the-TestRail-API"
      }
    ]
  },

